window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q06"]=window.__LIBQ["tien-nghich"]["q06"]||{};window.__LIBQ["tien-nghich"]["q06"]["factions"]={"updatedAt":"2026-06-24","count":90,"factions":[{"id":"lam-tong-thien-van-tong","name":"Lam tông (Thiên Vận Tông)","cn":"","type":"phan-he","typeLabel":"Phân hệ tông môn","diaBan":"Thiên Vận Tông","nhanVatChinh":["Tư Mã Như Phong"],"blurb":"Một phân hệ của Thiên Vận Tông; đệ tử mặc y phục lam thêu ba con lam long, Tư Mã Như Phong đứng hàng thứ hai.","detail":"Lam tông là một phân hệ đệ tử trong Thiên Vận Tông, song song với Tử hệ. Đệ tử Lam tông mặc y phục lam thêu ba con lam long; Tư Mã Như Phong đứng hàng thứ hai và tham gia cuộc vây kích Vương Lâm cùng đệ tử Lam tông hàng thứ hai khác.","nguon":["@c0458"]},{"id":"huyen-tran-lien-minh","name":"Huyền trấn liên minh","type":"lien-minh","typeLabel":"Liên minh","diaBan":"Bên ngoài khu vực Thiên Vận Tinh","nhanVatChinh":[],"blurb":"Liên minh lớn, phái sứ giả tới tặng quà mừng thọ Thiên Vận Tử — vinh dự hiếm có với một tu chân quốc cấp bảy.","detail":"Liên minh tầm cỡ lớn ngoài khu vực Thiên Vận Tinh; việc phái sứ giả tới tặng quà mừng đại thọ ngàn năm của Thiên Vận Tử được xem là vinh dự mà tu chân quốc cấp bảy hiếm ai có được, gợi mở thế lực này ở thang bậc cao hơn nhiều thất tông.","nguon":["@c0460"]},{"id":"van-la-tong","name":"Vân La Tông","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Vùng Thiên Vận Tinh","nhanVatChinh":[],"blurb":"Tông môn có tông chủ tu vi không kém, được Triệu Tinh Sát đặc biệt muốn kết giao tại thọ yến.","detail":"Tông môn được nhắc đến trong độc thoại của Triệu Tinh Sát: tông chủ tu vi không kém, hợp tính, là mục tiêu kết giao quan trọng nhất của hắn tại đại thọ ngàn năm của Thiên Vận Tử.","nguon":["@c0460"]},{"id":"thien-van-that-tu-tu-he","name":"Thiên Vận thất tử (cục diện Tử hệ)","type":"nhom","typeLabel":"Nhóm","diaBan":"Thiên Vận Tông","nhanVatChinh":["Triệu Tinh Sát"],"blurb":"Bảy đệ tử (tử) tranh danh hiệu Thiên Vận thất tử dưới trướng Thiên Vận Tử.","detail":"Cục diện bảy vị tử gồm: lão nhị đã bỏ cuộc, lão tam không được Triệu Tinh Sát để vào mắt, lão tứ là nữ có cách giữ chân, lão ngũ bị sư tôn phạt vào thiên ngục bế quan trăm năm, lão lục xuất ngoại lịch lãm sinh tử chưa rõ, lão thất bị Triệu Tinh Sát cảnh cáo chớ tranh đoạt danh hiệu.","nguon":["@c0460"]},{"id":"hoang-tong-thien-van","name":"Hoàng tông","cn":"","aliases":["Tử Hoàng nhị tông (Hoàng tông)"],"type":"tong-mon","typeLabel":"Tông phái","diaBan":"Thiên Vận Tinh","nhanVatChinh":[],"blurb":"Một trong hai mạch lớn của Thiên Vận Tông, cùng Tử tông hợp thành Tử Hoàng nhị tông tranh đoạt danh hiệu Thiên Vận Thất tử.","detail":"Hoàng tông là tông phái đối ứng với Tử tông trong Thiên Vận Tông. Một tháng sau thọ yến ngàn năm của Thiên Vận Tử, Tử Hoàng nhị tông sẽ tranh đoạt danh hiệu Thiên Vận Thất tử.","nguon":["@c0461"]},{"id":"sau-tong-phai-nho-thien-van-tinh","name":"Sáu tông phái nhỏ Thiên Vận Tinh","cn":"","type":"the-luc","typeLabel":"Cụm thế lực","diaBan":"Thiên Vận Tinh","nhanVatChinh":[],"blurb":"Sáu môn phái tầng dưới trên Thiên Vận Tinh, mỗi tông có một đại trưởng lão tu vi vấn đỉnh.","detail":"Sáu tông phái nhỏ phụ thuộc tầng dưới cùng trên Thiên Vận Tinh; mỗi tông cử một đại trưởng lão (tu vi từ vấn đỉnh sơ kỳ tới hậu kỳ đại viên mãn) tới dự tiệc thọ yến của Tử tông, ngồi phía bên trái bàn tiệc.","nguon":["@c0461"]},{"id":"thuy-van-mon","name":"Thủy Vân Môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"không rõ","nhanVatChinh":["Khương Thiên Tôn"],"blurb":"Tông môn có trưởng lão Khương Thiên Tôn ở cảnh giới Vấn Đỉnh Hậu Kỳ.","detail":"Thế lực có Khương Thiên Tôn làm trưởng lão Vấn Đỉnh Hậu Kỳ; ông là người nhận ra cổ yêu trong truyền thuyết thượng cổ và gọi tên Yêu lực khi quan sát trận đấu tại Thiên Vận Tông.","nguon":["@c0463"]},{"id":"xich-tong-thien-van","name":"Xích Tông","cn":"","type":"tong-mon","typeLabel":"Phân hệ Thiên Vận Tông","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Xích Liệt"],"blurb":"Phân hệ Xích của Thiên Vận Tông, hệ mạnh; đệ tử áo đỏ thêu kim long, đeo tiên hà noãn ngọc.","detail":"Một trong bảy hệ tông của Thiên Vận Tông (Xích, Chanh/Cam, Hoàng, Lục, Thanh, Lam, Tử). Trong lễ giảng đạo của Thiên Vận Tử, Xích Tông là đoàn xuất hiện đầu tiên kính bái tổng tông với bảy đệ tử áo đỏ thêu kim long, bên hông đeo tiên hà noãn ngọc. Xích Liệt là tiền bối hệ này, từng bắt Triệu Sát Tinh để sư ph��� trừng phạt.","nguon":["@c0464"]},{"id":"lam-tong-thien-van","name":"Lam Tông","cn":"","type":"tong-mon","typeLabel":"Phân hệ Thiên Vận Tông","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Tư Mã Như Phong"],"blurb":"Phân hệ Lam của Thiên Vận Tông; có Tư Mã Như Phong tu vi Anh Biến đại viên mãn gần Vấn Đỉnh.","detail":"Một trong bảy hệ tông Thiên Vận Tông, xuất hiện kính bái trong lễ giảng đạo Thiên Vận Tử. Có Tư Mã Như Phong đứng hàng thứ ba, tu vi Anh Biến đại viên mãn chỉ còn cách Vấn Đỉnh một chút.","nguon":["@c0464"]},{"id":"thanh-tong-thien-van","name":"Thanh Tông","cn":"","type":"tong-mon","typeLabel":"Phân hệ Thiên Vận Tông","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Nam tử họ Vương (Thanh Tông)"],"blurb":"Phân hệ Thanh của Thiên Vận Tông; có nam tử họ Vương mặt lạnh tu vi nửa bước Vấn Đỉnh.","detail":"Một trong bảy hệ tông Thiên Vận Tông, kính bái tổng tông trong lễ giảng đạo Thiên Vận Tử. Có một nam tử họ Vương mặt lạnh như băng đã bước nửa bước vào Vấn Đỉnh, tu vi vượt cả Tư Mã Như Phong của Lam Tông.","nguon":["@c0464"]},{"id":"cam-tong-thien-van","name":"Cam Tông","cn":"","aliases":["Chanh Tông"],"type":"tong-mon","typeLabel":"Phân hệ Thiên Vận Tông","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Người trung niên Cam Tông"],"blurb":"Phân hệ Cam (Chanh) của Thiên Vận Tông; đệ tử áo cam, có người trung niên dùng Sát Khí Huyết Tinh.","detail":"Một trong bảy hệ tông Thiên Vận Tông. Trong lễ giảng đạo, đoàn Cam Tông xuất hiện kính bái với đệ tử áo cam; vị trí thứ tư là người trung niên năm xưa từng đánh Sất Hổ ở tiên giới bằng Sát Khí Huyết Tinh, nay đã Anh Biến Hậu Kỳ.","nguon":["@c0464"]},{"id":"hoang-tong-thien-van-464","name":"Hoàng Tông","cn":"","type":"tong-mon","typeLabel":"Phân hệ Thiên Vận Tông","diaBan":"Thiên Vận Tinh","nhanVatChinh":[],"blurb":"Phân hệ Hoàng của Thiên Vận Tông, một trong bảy hệ tông.","detail":"Một trong bảy hệ tông Thiên Vận Tông (Xích, Chanh, Hoàng, Lục, Thanh, Lam, Tử), xuất hiện theo thứ tự kính bái tổng tông trong lễ giảng đạo Thiên Vận Tử.","nguon":["@c0464"]},{"id":"luc-tong-thien-van","name":"Lục Tông","cn":"","type":"tong-mon","typeLabel":"Phân hệ Thiên Vận Tông","diaBan":"Thiên Vận Tinh","nhanVatChinh":[],"blurb":"Phân hệ Lục của Thiên Vận Tông, một trong bảy hệ tông.","detail":"Một trong bảy hệ tông Thiên Vận Tông, xuất hiện kính bái tổng tông theo thứ tự trong lễ giảng đạo Thiên Vận Tử.","nguon":["@c0464"]},{"id":"that-he-de-tu-thien-van-tu","name":"Bảy hệ đệ tử của Thiên Vận Tử","type":"phan-he","typeLabel":"Phân hệ môn đồ","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Thiên Vận Tử","Vương Lâm","Bạch Vi","Tứ sư tỷ (Tử hệ)"],"blurb":"Bảy hệ đệ tử dưới trướng Thiên Vận Tử, phong hiệu cao nhất là Thiên Vận Thất tử.","detail":"Thiên Vận Tử có bảy hệ đệ tử, trong đó có Tử hệ và Hoàng hệ. Phong hiệu cao nhất mỗi hệ là Thiên Vận Thất tử; tại đại thọ vạn năm, chỉ Hoàng hệ và Tử hệ chưa ai nắm phong hiệu này. Hoàng hệ có sáu người, còn Tử hệ bị xem là quá yếu nên ít được chú ý.","nguon":["@c0468"]},{"id":"huyen-uyen-phai","name":"Huyền Uyên Phái","cn":"","type":"tong-mon","typeLabel":"Tu chân quốc","diaBan":"Địa Tinh","nhanVatChinh":["Lão Tổ Huyền Minh","Hứa Vân Sơn","Triệu Tứ"],"blurb":"Lục cấp tu chân quốc duy nhất trên Địa Tinh, tinh cầu phụ thuộc Thiên Vận Tử.","detail":"Huyền Uyên Phái là Lục cấp tu chân quốc duy nhất trên Địa Tinh, tự thành một quốc gia với đa phần dân là tu sĩ; đứng đầu là Lão Tổ Huyền Minh có tu vi vượt quá Vấn Đỉnh, dưới có Thiếu Tông Hứa Vân Sơn và nhiều Trưởng lão tóc bạc. Là tinh cầu phụ trực thuộc Thiên Vận Tử, phái lưu giữ ghi chép đầy đủ về đệ tử của Thiên Vận Tử và đặc biệt chú ý tới Thiên Vận Thất tử.","nguon":["@c0476"]},{"id":"linh-nhac-quoc","name":"Linh Nhạc quốc","cn":"","type":"quoc-gia","typeLabel":"Tu chân quốc","diaBan":"Địa Tinh","nhanVatChinh":[],"blurb":"Ngũ cấp tu chân quốc nhỏ trên Địa Tinh, nơi Vương Lâm tới nhậm chức sứ giả.","detail":"Linh Nhạc quốc là Ngũ cấp tu chân quốc trên Địa Tinh, cách Huyền Uyên Phái khoảng trăm vạn dặm về phía Tây. Tuy là nước nhỏ chỉ có bốn tông phái nhưng đặc sản Tý Linh vật nổi danh khắp Địa Tinh. Nước này coi việc đón sứ giả Tử hệ là vụ quan trọng hàng đầu, các tông phái chuẩn bị nghênh đón; trung tâm nước có một toà tháp chọc trời làm chỗ ở của các thế hệ sứ giả.","nguon":["@c0476"]},{"id":"ngu-linh-son-faction","name":"Ngũ Linh Sơn","cn":"","type":"tong-mon","typeLabel":"Tông phái / Thế lực","diaBan":"Linh Nhạc quốc, Thiên Vận Tinh","nhanVatChinh":["Thiên Thai lão nhân"],"blurb":"Thế lực tại Linh Nhạc quốc, nơi ở của Thiên Thai lão nhân — cao thủ đệ nhất quốc.","detail":"Ngũ Linh Sơn là nơi cư ngụ của Thiên Thai lão nhân, người tu vi cao nhất Linh Nhạc quốc. Trên đỉnh núi có thái âm lực để lão thổ nạp tu luyện.","nguon":["@c0477"]},{"id":"su-mon-thien-cam","name":"Sư môn của Thiên Cầm","cn":"","type":"tong-mon","typeLabel":"Sư môn","diaBan":"","nhanVatChinh":["Thiên Cầm cô nương","Nam tử áo trắng (đồng môn Thiên Cầm)"],"blurb":"Môn phái nhỏ ‘như đom đóm’ trước Đại La Kiếm Tông, đã hy sinh nhiều trưởng bối mới biết nơi có Diệu Kim quả.","detail":"Sư môn của Thiên Cầm là một môn phái nhỏ bé, đặt cạnh Đại La Kiếm Tông chỉ như đom đóm trước ánh trăng. Sư môn đã hy sinh mấy vị trưởng bối mới biết được vị trí có Diệu Kim quả nhưng không lấy được vì yêu thú thủ hộ. Có Đại trưởng lão đứng đầu, song khí tức kém xa hai Trưởng lão Anh Biến sơ kỳ của Đại La Kiếm Tông.","nguon":["@c0479"]},{"id":"kiem-tieu-thap-nhi-tu","name":"Kiếm Tiếu Thập Nhị Tử","cn":"","type":"nhom","typeLabel":"Nhóm cường giả","diaBan":"Đại La Kiếm Tông","nhanVatChinh":["Kiếm Tôn"],"blurb":"Mười hai cao thủ nòng cốt của Đại La Kiếm Tông đi theo Kiếm Tôn, mỗi người mang đại kiếm cổ huyễn hóa yêu thú.","detail":"Là lực lượng nòng cốt do Kiếm Tôn Lăng Thiên Hậu lập trong Đại La Kiếm Tông, đối trọng với Thiên Vận Thất Tử của Thiên Vận Tông. Mười hai người đều mang một thanh đại kiếm cổ huyễn hóa một loại yêu thú, có Yêu Linh thủ hộ.","nguon":["@c0487"]},{"id":"bo-toc-son-coc-au-duong-hoa","name":"Bộ tộc sơn cốc (bộ tộc Âu Dương Hoa)","cn":"","type":"khac","typeLabel":"Bộ tộc","diaBan":"Sơn cốc trong vùng đất Cổ yêu","nhanVatChinh":["Âu Dương Hoa"],"blurb":"Bộ tộc cư trú trong sơn cốc gồm các sinh vật thân trâu mình người toàn thân xích lõa, thờ yêu linh, được trận pháp thượng cổ bảo vệ.","detail":"Bộ tộc sống trong một sơn cốc, thành viên là những sinh vật thân trâu mình người toàn thân xích lõa, xanh xao vàng vọt nhưng ánh mắt hữu thần. Có trưởng lão Âu Dương Hoa và thượng cổ trận pháp bảo vệ. Bộ tộc thờ yêu linh, định lấy hồn phách người ngoài làm tế phẩm; theo Âu Dương Hoa, cứ bốn trăm năm lại có người ngoài tới một lần gây gió tanh mưa máu nên bộ tộc không chào đón.","nguon":["@c0493"]},{"id":"thien-yeu-quan","name":"Thiên Yêu quận","cn":"","type":"the-luc","typeLabel":"Thế lực yêu linh","diaBan":"Một trong chín quận của thiên hạ nơi yêu linh","nhanVatChinh":["Tai Hư","Âu Dương Hoa"],"blurb":"Một trong chín quận của thiên hạ nơi yêu linh; có yêu đế Tai Hư, bát đại yêu soái, thiên vạn yêu binh và hơn trăm thành trì.","detail":"Thiên Yêu quận là quận nơi sơn cốc của Vương Lâm tọa lạc, một trong chín quận của thiên hạ nơi yêu linh. Quận do yêu đế Tai Hư thống lĩnh, dưới có bát đại yêu soái, thiên vạn yêu binh và hơn trăm thành trì, nắm giữ một phương. Cổ yêu thành là một trong những thành trì của quận. Nghe đồn trong bát đại yêu soái từng có một vị trí do người bên ngoài nắm giữ — người bên ngoài cứ khoảng năm trăm năm lại vào nơi yêu linh, gia nhập các quận và lấy chiến công thăng tiến địa vị.","nguon":["@c0496"]},{"id":"bo-lac-son-coc-au-duong-hoa","name":"Bộ lạc sơn cốc (Âu Dương Hoa)","cn":"","type":"bo-lac","typeLabel":"Bộ lạc","diaBan":"Sơn cốc hình hồ lô thuộc Thiên Yêu quận, nơi man hoang","nhanVatChinh":["Âu Dương Hoa"],"blurb":"Bộ lạc cư dân nơi sơn cốc hình hồ lô, Âu Dương Hoa làm trưởng lão phụ trách dạy dỗ tộc nhân; dựa vào ngọc yêu linh để chữa trị.","detail":"Bộ lạc cư trú trong sơn cốc hình hồ lô thuộc nơi man hoang của Thiên Yêu quận. Âu Dương Hoa, sau khi học tập ở Cổ yêu thành đạt trình độ nhất tinh nhưng không được quyền ở lại, trở về làm trưởng lão dạy dỗ tộc nhân. Bộ lạc dựa vào ngọc yêu linh khảm trong vách đá đáy sơn cốc để chữa trị thương cho tộc nhân, sống dựa vào trận pháp che chở khỏi yêu linh đi săn vào đêm trăng tròn.","nguon":["@c0496"]},{"id":"thien-yeu-thanh","name":"Thiên Yêu Thành","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Hắc y nam tử (Thiên Vận Tinh)"],"blurb":"Thế lực mà Hắc y nam tử muốn tiến vào; muốn đủ tư cách vào thành phải thu lấy yêu tinh của yêu linh.","detail":"Một thế lực liên quan tới việc săn yêu linh trên Thiên Vận Tinh. Hắc y nam tử cần thu được yêu tinh (yêu linh) của con mồi để đủ tư cách tiến vào Thiên Yêu Thành, cho thấy thành đặt ra điều kiện gia nhập gắn với yêu lực kết tinh và yêu tinh.","nguon":["@c0497"]},{"id":"mon-phai-hac-y-nam-tu","name":"Môn phái của Hắc y nam tử","type":"khac","typeLabel":"Thế lực tu quỷ","diaBan":"Chưa rõ","nhanVatChinh":["Hắc y nhân (mặt sẹo)"],"blurb":"Thế lực nhắc qua công pháp tu luyện sản sinh quỷ tiên lực của Hắc y nam tử; chưa nêu tên.","detail":"Môn phái của Hắc y nam tử được nhắc qua công pháp tu luyện sản sinh quỷ tiên lực cùng bí thuật khống chế Quỷ ảnh bằng tơ đen mà hắn sử dụng. Tên thế lực và địa bàn cụ thể chưa được nêu trong chương.","nguon":["@c0500"]},{"id":"thien-quy-dao","name":"Thiên Quỷ Đạo","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Không rõ","nhanVatChinh":["La Vân","Quỷ Chân Nhân"],"blurb":"Môn phái của La Vân, tu Thiên Quỷ Đạo, có quỷ linh bảo vệ.","detail":"Tông môn tu công pháp Thiên Quỷ Đạo, đệ tử có quỷ linh bảo vệ. La Vân tự nhận uy thế tông môn tuy nghe khoa trương nhưng là lời thật, sư tôn Quỷ Chân Nhân địa vị ngang hàng Thiên Vận Tử. Vương Lâm nhận xét công pháp Thiên Quỷ ��ạo thú vị, trong đó có vài thuật ma cấm.","nguon":["@c0501"]},{"id":"phe-ta-thanh-co-yeu","name":"Phe tả thành (thành Cổ Yêu)","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Thành Cổ Yêu","nhanVatChinh":[],"blurb":"Thế lực ở thành Cổ Yêu, phần đông là cao thủ cư dân vùng đất yêu linh.","detail":"Phe tả thành ở thành Cổ Yêu gồm phần đông cao thủ cư dân vùng đất yêu linh, tu luyện lấy yêu lực và yêu lực thần thông làm chính. Là một trong các thế lực Vương Lâm phải vượt qua khi tới thành Cổ Yêu để đoạt Cổ yêu chi linh.","nguon":["@c0503"]},{"id":"tap-the-tu-luyen-son-coc-thien-van","name":"Tập thể tu luyện sơn cốc (Thiên Vận Tinh)","cn":"","type":"khac","typeLabel":"Nhóm tu luyện","diaBan":"Sơn cốc ở Thiên Vận Tinh","nhanVatChinh":["Vương Lâm","Âu Dương Hoa","Thập Tam"],"blurb":"Hai mươi bảy nam nhân trong sơn cốc tu luyện Luyện Hồn Yêu Thuật dưới quyền Vương Lâm.","detail":"Trong sơn cốc ở Thiên Vận Tinh có hai mươi bảy nam nhân tu luyện Luyện Hồn Yêu Thuật. Ngoài Thập Tam (giai đoạn ba), đại bộ phận còn ở giai đoạn một, sáu người chưa tu thành. Người cầm quyền đã chuyển từ Âu Dương Hoa sang Vương Lâm; nhóm dự định một tháng sau phát động tấn công một bộ tộc lân cận.","nguon":["@c0505"]},{"id":"bo-toc-cach-ngan-dam","name":"Bộ tộc cách ngàn dặm","cn":"","type":"khac","typeLabel":"Bộ tộc","diaBan":"Vùng đất rộng lớn cách sơn cốc ngàn dặm (Thiên Vận Tinh)","nhanVatChinh":[],"blurb":"Bộ tộc khoảng vài chục người, mục tiêu cuộc tấn công do Âu Dương Hoa lên kế hoạch.","detail":"Bộ tộc gồm khoảng vài chục người ở vùng đất rộng lớn cách sơn cốc của Vương Lâm ngàn dặm. Âu Dương Hoa định đợi chế xong hồn phiên sẽ phát động người trong cốc tiến công bộ tộc này; tuy đối phương đông hơn nhưng phe sơn cốc nắm Luyện Hồn Thuật nên kỳ vọng thắng lớn.","nguon":["@c0505"]},{"id":"bo-lac-luyen-hon","name":"Bộ lạc Luyện Hồn","cn":"","type":"khac","typeLabel":"Bộ lạc/tông phái mới","diaBan":"Thung lũng (Yêu Linh chi địa) + mảnh đất mười dặm cướp từ Thiên Thủy","nhanVatChinh":["Vương Lâm","Âu Dương Hoa","Lão già áo xám (Thiên Thủy)"],"blurb":"Bộ lạc mới do Vương Lâm lập, hơn năm trăm nam đinh, giống một môn phái tu chân mới sinh hơn bộ lạc Yêu linh thường.","detail":"Lập sau khi Vương Lâm giết lão áo trắng và thu nạp toàn bộ dân bộ lạc Thiên Thủy. Trung tâm là thung lũng cũ trở thành vùng cấm chỉ Vương Lâm ở, có thị vệ canh gác — tượng trưng quyền lực cao nhất. Phạm vi bảo vệ hai mươi dặm do dung hợp ba trận pháp. Mỗi tháng có đội ra ngoài đánh chiếm bộ lạc nhỏ, bắt tù binh và lấy về yêu tinh. Âu Dương Hoa là người đặt tên.","nguon":["@c0507"]},{"id":"bo-lac-thien-thuy","name":"Bộ lạc Thiên Thủy","cn":"","type":"khac","typeLabel":"Bộ lạc Yêu Linh chi địa","diaBan":"Đồng bằng phía Tây Bắc Yêu Linh chi địa","nhanVatChinh":["Lão già áo trắng (Thiên Thủy)","Lão già áo xám (Thiên Thủy)"],"blurb":"Bộ lạc dựa vào trận pháp viễn cổ mười dặm để chống Yêu Linh ban đêm; bị Vương Lâm xóa sổ, dân chúng thu vào bộ lạc Luyện Hồn.","detail":"Bốn bề trống trải nhưng trận pháp viễn cổ phủ mười dặm bảo vệ tuyệt đối kể cả khi Yêu Linh hạ xuống ban đêm. Lão áo trắng là chấp sự dưới trướng Tả Dực tướng quân ở Cổ Yêu thành về thăm người thân. Sau khi lão áo trắng bị Vương Lâm giết, lão áo xám mở trận pháp; toàn bộ tộc nhân bị thu nạp vào bộ lạc Luyện Hồn.","nguon":["@c0507"]},{"id":"co-yeu-thanh","name":"Cổ Yêu thành / phủ Tả Dực tướng quân","cn":"","type":"khac","typeLabel":"Thành thị Yêu Linh chi địa","diaBan":"Yêu Linh chi địa","nhanVatChinh":["Tả Dực tướng quân","Lão già áo trắng (Thiên Thủy)"],"blurb":"Thành lớn có quân chế, Tả Dực tướng quân thống lĩnh, trong phủ có hàng Trưởng lão tu vi ngang Vương Lâm.","detail":"Lão áo trắng làm chấp sự/chấp phụ dưới trướng Tả Dực tướng quân; người từ bên ngoài đến có thể tới tìm chức vụ. Lão áo xám định báo việc Vương Lâm lên phủ Tả Dực nhưng sợ hãi bỏ ý định sau khi chứng kiến uy lực Vương Lâm.","nguon":["@c0507"]},{"id":"yeu-toc-the-luc-yeu-de","name":"Thế lực yêu tộc (Yêu đế)","cn":"","type":"chung-toc","typeLabel":"Chủng tộc / Thế lực","diaBan":"Cổ Yêu thành","nhanVatChinh":["Yêu đế","Tả Dực tướng quân"],"blurb":"Thế lực yêu tộc đứng đầu là Yêu đế, dưới có các chức Đô thống, Nghiêu lĩnh, trường nham; Tả dực Yêu tướng phụng mệnh đi tìm kiếm một người nhất định.","detail":"Thế lực yêu tộc do Yêu đế thống lĩnh, đóng tại Cổ Yêu thành. Trong hàng ngũ có các chức vị như Đô thống, Nghiêu lĩnh và ‘trường nham’ (vị trí Tả dực Yêu tướng dành cho Vương Lâm khi đuổi hắn lui). Tả dực Yêu tướng phụng mệnh Yêu đế đi tìm kiếm một người nhất định, đặt nghi vấn về đối tượng yêu tộc đang truy tìm.","nguon":["@c0511"]},{"id":"nghieu-linh","name":"Nghiêu Lĩnh","cn":"","type":"khac","typeLabel":"Chức vị quân yêu","diaBan":"Cổ Yêu thành","nhanVatChinh":["Thống lĩnh (Nghiêu Lĩnh, Cổ Yêu thành)","Yêu Tương đại nhân"],"blurb":"Danh hiệu chức vị thống lĩnh trong quân yêu ở Cổ Yêu thành, gồm Nghiêu Lĩnh chính và Nghiêu Lĩnh phó.","detail":"Chức vị chỉ huy quân yêu hắc giáp ở Cổ Yêu thành, chia làm Nghiêu Lĩnh chính và phó. Người ngoài đến được Yêu Tương đại nhân phá lệ phong làm Nghiêu Lĩnh chính, khiến thống lĩnh cũ bị phế chức sinh bất mãn và tìm cách trả đũa.","nguon":["@c0513"]},{"id":"quan-doanh-yeu-tuong","name":"Quân doanh (dưới trướng Yêu Tương)","cn":"","type":"quan-su","typeLabel":"Quân sự yêu tộc","diaBan":"Yêu Linh chi địa","nhanVatChinh":["Yêu Tương","Yêu đế","Vương Lâm"],"blurb":"Doanh trại yêu binh dưới trướng Yêu Tương / Yêu đế, nơi Vương Lâm được đưa tới nhậm chức thống lĩnh.","detail":"Quân doanh xây bằng đá đen, chu vi ước trăm dặm, tường thành được gia trì pháp thuật có yêu lực dao động. Bên trong chứa hơn mười đội yêu binh giáp đen, mỗi đội một ngàn người, tổng cộng hơn vạn; yêu lực không ai kém tam thập giáp, có người vượt trăm, tất cả đều từng qua sa trường, sát khí thâm nhập xương tủy. Truyền Tống trận do Yêu đế tạo dùng để đưa người ra vào.","nguon":["@c0514"]},{"id":"hac-giap-quan","name":"Hắc Giáp quân","type":"quan-doi","typeLabel":"Quân đội yêu binh","diaBan":"Yêu Linh chi địa","nhanVatChinh":["Vương Lâm","Tư Mã Viêm"],"blurb":"Đạo quân yêu binh một vạn người mặc giáp đen ở Yêu Linh chi địa, do Vương Lâm nhậm chức tân thống lĩnh và Tư Mã Viêm làm phó thống lĩnh.","detail":"Hắc Giáp quân là đạo quân gồm một vạn yêu binh mặc giáp đen thuộc Yêu Linh chi địa, tiếng hét đồng loạt ẩn yêu lực và sát khí không kém một tu sĩ Anh Biến rống. Quân được tổ chức theo mười đội, mỗi đội khoảng ngàn người do một Thống đội cai quản; mười Thống đội là tâm phúc của phó thống lĩnh Tư Mã Viêm. Vương Lâm được phái tới nhậm chức tân thống lĩnh, song yêu binh chỉ nghe lệnh Tư Mã Viêm và công khai khinh thường vị thống lĩnh mới.","nguon":["@c0515"]},{"id":"cuu-quan-yeu-binh","name":"Cửu quận yêu binh","aliases":["Cửu quận yêu linh"],"type":"the-luc","typeLabel":"Thể chế quân sự","diaBan":"Yêu Linh chi địa","nhanVatChinh":["Yêu Tương đại nhân"],"blurb":"Hệ thống chín quận của Yêu Linh chi địa, lấy quân pháp làm gốc, mỗi quận có một Yêu Đế; người ngoài muốn đặt chân phải tuyển nhập nắm binh quyền.","detail":"Cửu quận yêu binh là thể chế chín quận của Yêu Linh chi địa, lấy quân pháp làm gốc, khác hẳn tu chân giới. Trừ phi có tu vi thông thiên đánh được với Yêu Đế, mọi người vào đây đều phải tuyển dung nhập quận nắm binh quyền mới có chỗ đặt chân và tuân quân quy; phản quân quy sẽ mất tất cả. Quy định còn nêu một người không nghe hiệu lệnh có thể bị khiển trách, nhưng mười người không nghe thì khó xử. Yêu binh tu vi không cao nhưng có cao thủ và am hiểu trận pháp quỷ dị; giết nhiều yêu binh sẽ dẫn ra đô thống và cường giả cấp Yêu Tương. Chỉ khi lập chiến công mới có cơ hội dung hợp Cổ yêu.","nguon":["@c0515"]},{"id":"muoi-thong-doi-tu-ma-viem","name":"Mười Thống đội (tâm phúc Tư Mã Viêm)","type":"the-luc","typeLabel":"Nhóm chỉ huy","diaBan":"Quân doanh Hắc Giáp quân","nhanVatChinh":["Tư Mã Viêm","Từ U","Chu Khải"],"blurb":"Mười người chỉ huy các đội ngàn người trong Hắc Giáp quân, là tâm phúc của phó thống lĩnh Tư Mã Viêm.","detail":"Mỗi đội khoảng ngàn yêu binh của Hắc Giáp quân có một Thống đội cai quản; mười Thống đội này là tâm phúc của Tư Mã Viêm, giúp hắn nắm thực quyền cả vạn yêu binh. Tuy nhiên hai người Từ U và Chu Khải ít lui tới Tư Mã Viêm và vắng mặt khi được triệu tập, hé lộ khe hở phe phái trong nội bộ.","nguon":["@c0515"]},{"id":"thien-yeu-quan-faction","name":"Thiên Yêu quận","cn":"","type":"the-luc","typeLabel":"Thế lực quân sự","diaBan":"Thiên Yêu quận","nhanVatChinh":["Vương Lâm","Tư Mã Viêm"],"blurb":"Thế lực có hệ thống quân quy đánh số áp dụng trong quân doanh, quản lý yêu binh, thống đội và thống lĩnh.","detail":"Thiên Yêu quận là tổ chức quân sự có hệ thống quân quy chặt chẽ (điều hai, điều tám, điều mười ba…) chi phối hành xử trong quân doanh, phân cấp từ yêu binh, thống đội, thống lĩnh đến quản sự tham quân ở tầng cao hơn. Vương Lâm được bổ làm thống lĩnh mới của một quân doanh hơn vạn yêu binh; Tư Mã Viêm là thống lĩnh đối đầu tranh giành quyền lực. Chính việc viện dẫn quân quy đã giúp Vương Lâm xoay chuyển thế cờ khi bị vây.","nguon":["@c0516"]},{"id":"huyet-phu","name":"Huyết Phủ","type":"the-luc","typeLabel":"Thế lực","diaBan":"Yêu Linh chi địa","nhanVatChinh":["Huyết Tổ Diêu Tinh Hải","Diêu Tích Tuyết"],"blurb":"Thế lực gắn với Huyết Tổ; có lệnh bài Huyết Phủ mà Diêu Tích Tuyết hứa trao Vương Lâm.","detail":"Thế lực do Huyết Tổ Diêu Tinh Hải đứng đầu, con gái ông là Diêu Tích Tuyết. Sở hữu lệnh bài Huyết Phủ làm tín vật, gắn với các bí pháp như Huyết Hồn đan, trận ẩn thân và truyền tống trận trong Yêu Linh chi địa.","nguon":["@c0520"]},{"id":"yeu-ve","name":"Yêu Vệ","type":"khac","typeLabel":"Chức vị / Lực lượng","diaBan":"Lãnh thổ Yêu Linh","nhanVatChinh":["Lão già hắc bào (ân công của Hổ Bào)","Hổ Bào"],"blurb":"Cấp bậc lực lượng mà lão già hắc y định bồi dưỡng Hổ Bào trở thành qua khẩu quyết bí thuật của chủ nhân.","detail":"Yêu Vệ là cấp bậc hay lực lượng mà lão già hắc bào dự định biến Hổ Bào trở thành. Kế hoạch là cho Hổ Bào hấp thụ lượng lớn hồn phách bằng Luyện Hồn Thuật, phối hợp công pháp và đan dược của lão, rồi tu khẩu quyết của chủ nhân để ngưng tụ toàn bộ tuổi thọ và tiềm lực bùng nổ trong một canh giờ mà biến thành Yêu Vệ.","nguon":["@c0530"]},{"id":"co-yeu-dien","name":"Cổ Yêu điện","type":"co-quan","typeLabel":"Cơ cấu yêu tộc","diaBan":"Kinh thành Thiên Yêu quận (gắn liền cuộc chiến Yêu tướng)","nhanVatChinh":[],"blurb":"Thánh địa tu luyện dành cho các Yêu tướng đạt thành tích cao trong cuộc chiến Yêu tướng; ra khỏi đây liền giữ chức phó soái.","detail":"Mạc Lực Hải nhắm tới Cổ Yêu điện như phần thưởng nếu lọt vào vòng ba cuộc chiến giữa các Yêu tướng; hoàn tất tu luyện trong điện đồng nghĩa với việc thăng lên chức phó soái cấp quận.","nguon":["@c0531"]},{"id":"bo-lac-luyen-hon-faction","name":"Bộ lạc Luyện Hồn","type":"bo-toc","typeLabel":"Bộ lạc","diaBan":"Sơn cốc vùng Yêu Linh","nhanVatChinh":["Vương Lâm","Âu Dương Hoa"],"blurb":"Bộ lạc do Vương Lâm âm thầm khống chế qua Âu Dương Hoa; lấy Luyện Hồn Thuật làm vốn liếng, đặt mục tiêu bành trướng tới hơn trăm vạn tộc nhân.","detail":"Vương Lâm xếp đặt Âu Dương Hoa làm chi chính, dùng Hồn Phiên thường phủ kín bầu trời sơn cốc thay Tôn Hồn Phiên, đồng thời phái mấy trăm tộc nhân tiềm nhập các bộ lạc lớn nhỏ — chống Linh Thang Loạn Thần bằng Hồn Phách Thủ Thần — để truyền Luyện Hồn Thuật ra ngoài. Chi chính nắm phần hai pháp môn (thần thông rút phách).","nguon":["@c0531"]},{"id":"hoa-yeu-quan","name":"Hỏa Yêu quận","type":"the-luc","typeLabel":"Cường quốc yêu tộc","diaBan":"Giáp biên giới Thiên Yêu quận","nhanVatChinh":[],"blurb":"Thế lực yêu tộc đối địch với Thiên Yêu quận, từng gây đại chiến khiến hai phó soái Thiên Yêu quận tử trận.","detail":"Hỏa Yêu quận là cường quốc yêu tộc giáp ranh và thù địch với Thiên Yêu quận. Hai trăm năm trước, đại chiến giữa hai bên khiến hai phó soái của Thiên Yêu quận tử trận, để lại hai vị trí soái trống mà cuộc chiến Yêu tướng lần này phải tuyển bổ. Yêu tướng Mặc Phi hiện trấn thủ đoạn biên giới giáp Hỏa Yêu quận.","nguon":["@c0532"]},{"id":"mac-phu","name":"Mạc phủ","cn":"","type":"the-luc","typeLabel":"Phủ đệ","diaBan":"Hồng thành","nhanVatChinh":["Mạc Lực Hải"],"blurb":"Phủ đệ của Mạc Lệ Hải tại Hồng thành, có gia binh canh gác; nơi Vương Lâm tá túc trong thời gian ở Hồng thành.","detail":"Mạc phủ là phủ đệ của yêu tu Mạc Lệ Hải đặt tại Hồng thành, có gia binh tuần phòng. Vương Lâm tá túc tại đây và từ đây thương lượng với Mạc Lệ Hải về việc được sắp xếp vào Hồng lao tu luyện giết chóc.","nguon":["@c0535"]},{"id":"bat-dai-yeu-soai-thien-yeu-quan","name":"Bát đại Yêu Soái","cn":"","type":"che-do","typeLabel":"Chế độ/Thế lực","diaBan":"Thiên Yêu Quận","nhanVatChinh":[],"blurb":"Tám Yêu Soái của Thiên Yêu Quận, mỗi soái ứng một thành; soái danh lấy theo Thiên, Địa, Huyền, Hoàng, Vũ, Trụ, Hồng, Hoang.","detail":"Bát đại Yêu Soái của Thiên Yêu Quận lấy soái danh theo Thiên, Địa, Huyền, Hoàng, Vũ, Trụ, Hồng, Hoang. Mỗi Yêu Soái ứng với một tòa thành ngoài. Phủ Yêu Soái không có phó soái, mà phó soái đóng tại các thành.","nguon":["@c0537"]},{"id":"hoa-yeu-quan-thien-yeu","name":"Hỏa Yêu Quận","cn":"","type":"the-luc","typeLabel":"Quận yêu tộc","diaBan":"Biên giới Thiên Yêu","nhanVatChinh":["Mặc Phi"],"blurb":"Quận yêu tộc ở biên giới, có Yêu Tương Mặc Phi là một trong đệ nhất nhân.","detail":"Hỏa Yêu Quận ở vùng biên giới, có Yêu Tương Mặc Phi — một trong đệ nhất nhân ở biên giới Hỏa Yêu Quận, đóng tại Vũ Thành.","nguon":["@c0537"]},{"id":"yeu-toc-thien-yeu-thanh-yeu-tuong","name":"Yêu tộc Thiên Yêu Thành (hệ Yêu Tướng - Yêu Soái)","cn":"","type":"the-luc","typeLabel":"Thế lực quân sự","diaBan":"Thiên Yêu Thành","nhanVatChinh":["Mạc Lệ Hải","Phó soái Huyền Thành","Yêu đế"],"blurb":"Tổ chức quân sự yêu tộc tại Thiên Yêu Thành với các cấp Yêu Tướng, phó soái, Yêu Soái.","detail":"Tổ chức quân sự yêu tộc tại Thiên Yêu Thành, phân các cấp Yêu Tướng, phó soái và Yêu Soái. Phó soái Huyền Thành sắp đột phá lên Yêu Soái. Có đại hội Yêu Tướng sắp diễn ra, nơi Mạc Lệ Hải tranh chức phó soái với sự trợ giúp của Vương Lâm.","nguon":["@c0538"]},{"id":"nhom-sat-thu-lao-to","name":"Nhóm sát thủ của lão tổ","cn":"","type":"to-chuc","typeLabel":"Tổ chức sát thủ","diaBan":"","nhanVatChinh":["Nam tử lớn tuổi áo đen (đầu lĩnh sát thủ)","Sát thủ số hai (thanh niên áo đen)","Sát thủ số bốn (trung niên mắt sáng)"],"blurb":"Tổ chức sát thủ đánh số thứ tự, khí tức tiên yêu dung hợp, nhận lệnh lão tổ truy bắt Vương Lâm.","detail":"Tổ chức sát thủ với các thành viên được đánh số (số hai, số ba, số bốn, số năm…), thân tỏa khí tức tiên yêu dung hợp kỳ dị. Có đầu lĩnh áo đen lớn tuổi điều phối trên tửu lầu. Nhận lệnh “lão tổ” chỉ đích danh bắt Vương Lâm không cho chạy thoát. Tên tổ chức chưa rõ; thủ lĩnh tối cao lão tổ chưa lộ diện.","nguon":["@c0540"]},{"id":"cu-linh-mon","name":"Cự Linh Môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Thiên Khôi Công Nhân"],"blurb":"Môn phái lớn trên Thiên Vận Tinh, thần thông thiên về sức lực.","detail":"Môn phái lớn trên Thiên Vận Tinh, thần thông thiên về sức lực tương tự Cự Ma Tộc. Thiên Khôi Công Nhân — trợ giúp của Mộ Vân trong trận Yêu Tướng — xuất thân từ đây.","nguon":["@c0543"]},{"id":"long-dam-co-yeu-dien-truyen-thua","name":"Long Đàm Cổ Yêu Điện","cn":"","type":"truyen-thua","typeLabel":"Truyền thừa","diaBan":"Thiên Yêu Quận","nhanVatChinh":["Ma Văn"],"blurb":"Truyền thừa công pháp đặc biệt mà Yêu Tướng Ma Văn kế thừa.","detail":"Truyền thừa gắn với Long Đàm Cổ Yêu Điện của Thiên Yêu Quận, công pháp đặc biệt. Yêu Tướng Ma Văn là người kế thừa truyền thừa này.","nguon":["@c0543"]},{"id":"thien-yeu-mon","name":"Thiên Yêu Môn","type":"the-luc","typeLabel":"Thế lực yêu tộc","diaBan":"Đế Đô, Thiên Yêu quận","nhanVatChinh":["Nam tử mặc giáp vàng","Vu Sâm","Ngao Địch"],"blurb":"Thế lực yêu tộc tổ chức đại hội Yêu Tướng trên quảng trường vạn trượng đầy cấm chế.","detail":"Thiên Yêu Môn tổ chức đại hội Yêu Tướng trên quảng trường vạn trượng đầy cấm chế tại Đế Đô. Phân cấp trong yêu tộc gồm Yêu Tướng – Yêu Soái – Yêu Đế. Kim tổng quản (nam tử mặc giáp vàng) phụ trách điều hành đại hội; quảng trường có khán đài bốn phía và hai khán đài nam bắc dành cho tám Yêu Soái. Cu���i ngày đầu, đám Yêu Tướng theo Thiên Yêu Môn về nơi ở.","nguon":["@c0544"]},{"id":"ngoc-kiem-mon","name":"Ngọc Kiếm Môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Yêu Linh / Thiên Yêu Thành","nhanVatChinh":["Thiếu môn chủ Ngọc Kiếm Môn (nam tử áo trắng)"],"blurb":"Tông môn có thiếu môn chủ là nam tử áo trắng; bị cuốn vào tranh đoạt Yêu Tướng rồi dẫn đoàn tu sĩ rời khỏi Thiên Yêu Thành.","detail":"Ngọc Kiếm Môn là tông môn mà thiếu môn chủ là một nam tử áo trắng tướng mạo sáng sủa. Bị cuốn vào tranh đoạt Yêu Tướng tại Thiên Yêu Thành, sau khi thức tỉnh rằng tu sĩ ở Yêu Linh chỉ là con hát mua vui, sinh mạng thấp hơn kiến, thiếu môn chủ dẫn đoàn tu sĩ Anh Biến kỳ trở lên rời khỏi Thiên Yêu Thành, hóa cầu vồng bay đi.","nguon":["@c0545"]},{"id":"dai-la-kiem-tong","name":"Đại La Kiếm Tông","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Vùng đất Yêu Linh / Thiên Vận Tinh","nhanVatChinh":["Mạt Dương","Lăng Thiên Hậu"],"blurb":"Tông môn kiếm tu của Mạt Dương, có nhóm Kiếm Tiếu Thập Nhị Tử và sư tôn Lăng Thiên Hậu.","detail":"Tông môn của Mạt Dương, sở hữu nhóm tinh anh Kiếm Tiếu Thập Nhị Tử và sư tôn Lăng Thiên Hậu ban kiếm khí bảo mệnh. Tại vùng đất Yêu Linh, Vương Lâm tuyên bố không muốn đối địch với Đại La Kiếm Tông nên tha Mạt Dương rồi nhờ chuyển lời.","nguon":["@c0541"]},{"id":"kiem-tieu-thap-nhi-tu-dai-la","name":"Kiếm Tiếu Thập Nhị Tử (Đại La Kiếm Tông)","cn":"","type":"nhom","typeLabel":"Nhóm tinh anh","diaBan":"Đại La Kiếm Tông","nhanVatChinh":["Mạt Dương","Lăng Thiên Hậu"],"blurb":"Nhóm mười hai đệ tử tinh anh của Đại La Kiếm Tông, mỗi người được Lăng Thiên Hậu ban một đạo kiếm khí bảo mệnh.","detail":"Mười hai đệ tử tinh anh trong Đại La Kiếm Tông, địa vị tương đương Thiên Vận Thất Tử; mỗi người được sư tôn Lăng Thiên Hậu ban một đạo kiếm khí bảo mệnh là sát chiêu tối hậu. Mạt Dương là một trong nhóm này.","nguon":["@c0541"]},{"id":"de-toc-thien-yeu-quan","name":"Đế tộc Thiên Yêu quận","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Thiên Yêu quận","nhanVatChinh":[],"blurb":"Tầng lớp chỉ riêng người trong Đế tộc mới có tư cách dùng sức mạnh Cổ Yêu để tẩy tủy.","detail":"Đế tộc của Thiên Yêu quận là tầng lớp duy nhất có tư cách dùng sức mạnh Cổ Yêu để tẩy tủy. Người ngoài Đế tộc phải lập công hiển hách mới được ban thưởng cơ hội gõ Yêu Cổ tẩy tủy.","nguon":["@c0549"]},{"id":"cac-trieu-yeu-de","name":"Các triều đại Yêu Đế","cn":"","type":"the-luc","typeLabel":"Truyền thừa","diaBan":"Thiên Yêu quận","nhanVatChinh":[],"blurb":"Các triều đại Yêu Đế dùng phương pháp truyền thừa gõ Yêu Cổ rút sức mạnh Cổ Yêu.","detail":"Các triều đại Yêu Đế của Thiên Yêu quận đời nối đời dùng phương pháp truyền thừa gõ Yêu Cổ để rút sức mạnh Cổ Yêu, bảo vệ Thiên Yêu quận vạn vạn năm vinh quang.","nguon":["@c0549"]},{"id":"cac-lao-to-tong-thien-yeu","name":"Các lão tổ tông (thế lực ẩn)","type":"the-luc-an","typeLabel":"Thế lực ẩn","diaBan":"Mảnh đất Yêu Linh","nhanVatChinh":[],"blurb":"Thế lực ẩn được người thanh niên trên thuyền hoa nhắc tới khi thiên uy giáng lâm, chưa rõ danh tính cụ thể.","detail":"Khi thiên uy giáng xuống Thiên Yêu Thành, người thanh niên lo lắng nhắc tới “các lão tổ tông”, chẳng biết có xuất hiện hay không. Đây là thế lực ẩn được gợi mở qua biến cố thiên uy bất thường, gắn với những biến cố lớn sắp tới của mảnh đất Yêu Linh.","nguon":["@c0553"]},{"id":"toc-co","name":"Tộc Cổ","cn":"","type":"chung-toc","typeLabel":"Chủng tộc nghịch thiên","diaBan":"Vũ trụ sơ khai","nhanVatChinh":[],"blurb":"Chủng tộc thời vũ trụ sơ khai đồng trang lứa với thiên đạo, tự xưng Cổ, là sinh linh nghịch tu thứ nhất.","detail":"Tộc Cổ là chủng tộc thời vũ trụ sơ khai, đồng trang lứa với thiên đạo, lực lượng vô cùng lớn — dùng lực chứng đạo nghịch thiên, dùng thần thông diệt đạo kháng thiên, dùng sát lục tử biến thiên. Tự xưng Cổ, là sinh linh nghịch tu thứ nhất; thiên kiếp không hủy diệt được, thiên uy không khuất phục được. Về sau phân chia thành ba nhánh: Cổ Thần (lực lượng khổng lồ), Cổ Ma (sát lục), Cổ Yêu (thần thông diệt đạo).","nguon":["@c0554"]},{"id":"co-yeu-nhanh","name":"Cổ Yêu","cn":"","type":"chung-toc","typeLabel":"Nhánh tộc Cổ","diaBan":"Đế Đô Thiên Yêu thành","nhanVatChinh":["Năm lão già Cổ Yêu"],"blurb":"Nhánh thần thông diệt đạo của tộc Cổ, là sinh linh nghịch tu thứ hai; năm lão già ở Đế Đô tự xưng con cháu Cổ Yêu.","detail":"Cổ Yêu là nhánh chuyên thần thông diệt đạo của tộc Cổ sau khi phân chia, là sinh linh nghịch tu thứ hai. Năm lão già từ lòng đất Đế Đô Thiên Yêu thành tự xưng con cháu Cổ Yêu, đã thoát trói buộc thiên đạo. Giọng nói âm u giảng giải cho Vương Lâm cũng tự xưng Ta là Cổ Yêu.","nguon":["@c0554"]},{"id":"co-than-nhanh","name":"Cổ Thần","cn":"","type":"chung-toc","typeLabel":"Nhánh tộc Cổ","diaBan":"","nhanVatChinh":[],"blurb":"Nhánh có lực lượng khổng lồ của tộc Cổ sau khi phân chia, là sinh linh nghịch tu thứ hai.","detail":"Cổ Thần là nhánh có lực lượng khổng lồ nhất của tộc Cổ sau khi tộc Cổ phân chia, là sinh linh nghịch tu thứ hai.","nguon":["@c0554"]},{"id":"co-ma-nhanh","name":"Cổ Ma","cn":"","type":"chung-toc","typeLabel":"Nhánh tộc Cổ","diaBan":"","nhanVatChinh":[],"blurb":"Nhánh chuyên sát lục huyết tinh của tộc Cổ, khiến sinh linh đồ thán, là sinh linh nghịch tu thứ hai.","detail":"Cổ Ma là nhánh chuyên sát lục huyết tinh của tộc Cổ sau khi phân chia, khiến sinh linh đồ thán, là sinh linh nghịch tu thứ hai.","nguon":["@c0554"]},{"id":"cuu-quan-yeu-linh","name":"Cửu quận Yêu Linh","type":"lien-minh","typeLabel":"Hệ thế lực Yêu Linh","diaBan":"Lãnh thổ Yêu Linh","nhanVatChinh":["Cổ Yêu"],"blurb":"Chín Yêu quận lãnh thổ Yêu Linh, mỗi quận có một tồn tại không hoàn chỉnh cai quản và một nơi kiểu Long Đàm.","detail":"Lãnh thổ Yêu Linh có chín Yêu quận, mỗi quận đặt dưới sự dẫn dắt của một tồn tại không hoàn chỉnh tương tự Cổ Yêu của Thiên Yêu quận. Mỗi bên đều lập một nơi giống Long Đàm để giáo dục con dân. Các tồn tại từng liên lạc nhưng đều muốn thôn phệ lẫn nhau để trở nên hoàn chỉnh, sinh ra chiến tranh chín quận Yêu Linh kéo dài nhiều năm; tu sĩ xuất hiện không ảnh hưởng thắng bại nên được dung thân ở đây. Thiên Yêu quận là một trong chín, có thánh vật riêng; Cổ Yêu giao Vương Lâm thu hồi thánh vật tám quận còn lại.","nguon":["@c0555"]},{"id":"con-lon-luyen-khi-si","name":"Côn Lôn Luyện Khí Sĩ","type":"tong-mon","typeLabel":"Thế lực tu luyện viễn cổ","diaBan":"Viễn cổ (đã không còn rực rỡ)","nhanVatChinh":[],"blurb":"Đại biểu điển hình của tu giả thời viễn cổ tự xưng Luyện Khí Sĩ.","detail":"Côn Lôn Luyện Khí Sĩ là đại biểu điển hình của tu luyện giả thời viễn cổ tự xưng Luyện Khí Sĩ, từng oai dũng một thời. Họ luyện Nguyên Khí rút ra ngoài làm lực lượng, không dùng tiên lực; được nhắc trong lý luận về nguyên khí - chân nguyên mà Vương Lâm ngộ ra khi tiến Vấn Đỉnh.","nguon":["@c0555"]},{"id":"phu-pho-soai-thien-yeu-quan-556","name":"Phủ Phó soái","cn":"","type":"quan-su","typeLabel":"Cơ cấu quân sự","diaBan":"Cửa đông một tòa thành Thiên Yêu quận","nhanVatChinh":["Đại hán Phó soái (mặc Soái bào)"],"blurb":"Phủ đệ tôn quý ở cửa đông một tòa thành trong Thiên Yêu quận, biển treo “Phủ Phó soái”, nhiều người hầu.","detail":"Phủ đệ tôn quý nằm tại cửa đông một tòa thành thuộc Thiên Yêu quận, biển treo “Phủ Phó soái”. Có đại hán mặc Soái bào làm chủ phủ cùng ba Yêu tướng cung kính theo hầu; mười năm sau biến cố, chủ phủ vẫn nhìn trời than nhớ Vương Lâm.","nguon":["@c0556"]},{"id":"mon-phai-mac-to","name":"Mạc Tổ (sư đồ Ma Vực)","type":"khac","typeLabel":"Sư đồ / thế lực","diaBan":"Tinh cầu Ma Vực, Thiên Vận Tinh","nhanVatChinh":["Mạc Tổ","Hai đệ tử Mạc Tổ"],"blurb":"Thế lực sư đồ do Mạc Tổ đứng đầu ở tinh cầu Ma Vực trên Thiên Vận Tinh, có ba đệ tử thân truyền.","detail":"Mạc Tổ tu vi Âm Dương Hư Thực nhị ý, ở tinh cầu Ma Vực trên Thiên Vận Tinh, vượt mức tư cách vào mảnh đất Yêu Linh. Ông có ba đệ tử thân truyền; hai đệ tử Anh Biến hậu kỳ vào đất Yêu Linh đã bị Vương Lâm giết vì tham đoạt Yêu Tinh, đệ tử đứng đầu không vào nên còn sống.","nguon":["@c0559"]},{"id":"luyen-canh-tong","name":"Luyện Cảnh tông","type":"tong-mon","typeLabel":"Tông môn","diaBan":"","nhanVatChinh":["Độn Thiên"],"blurb":"Tông môn của Độn Thiên — người mà theo truyền thuyết Vương Lâm bái làm sư phụ.","detail":"Tông môn của Độn Thiên. Theo truyền thuyết được kể ở Vân Thiên Tông, Vương Lâm từng bái Độn Thiên của Luyện Cảnh tông làm sư phụ.","nguon":["@c0567"]},{"id":"kiem-ton-the-luc","name":"Kiếm Tôn","cn":"","type":"khac","typeLabel":"Thế lực","diaBan":"Vùng Yêu Linh","nhanVatChinh":["Mặc Phi"],"blurb":"Nhóm có đệ tử nắm giữ mười đạo kiếm khí, mục tiêu Vương Lâm muốn giết để đoạt kiếm khí.","detail":"Kiếm Tôn là thế lực có đệ tử nắm giữ những đạo kiếm khí. Vương Lâm dự định giết từng đệ tử Kiếm Tôn để thu mười đạo kiếm khí còn lại, từ đó luyện hóa khí sát lục để có năng lực sống yên ổn ở vùng Yêu Linh. Hai đệ tử Kiếm Tôn từng ở bên cạnh Mặc Phi là mục tiêu chính.","nguon":["@c0570"]},{"id":"to-linh-the-luc","name":"Tổ Linh","cn":"","type":"khac","typeLabel":"Thế lực/Thực thể","diaBan":"","nhanVatChinh":[],"blurb":"Thực thể/thế lực được tôn kính trong yêu tộc; Vương Lâm được Yêu Đế tuyên bố là sứ giả Tổ Linh chỉ điểm.","detail":"Tổ Linh là thực thể được yêu tộc tôn kính. Yêu Đế Cổ Vân Phong tuyên bố ra ngoài rằng Vương Lâm là sứ giả của Tổ Linh chỉ điểm để hắn dễ làm việc, đồng thời trao ngọc giản kèm theo thân phận này.","nguon":["@c0570"]},{"id":"bo-lac-luyen-hon-573","name":"Bộ lạc Luyện Hồn","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Đất Yêu Linh","nhanVatChinh":["Vương Lâm","Âu Dương Hoa"],"blurb":"Bộ tộc tu thuật Luyện Hồn tại đất Yêu Linh, tôn Vương Lâm làm Lão tổ.","detail":"Bộ tộc tu thuật Luyện Hồn cư trú tại đất Yêu Linh, phát triển cực nhanh, tôn Vương Lâm làm Lão tổ kiêm người thủ hộ. Có tháp cao ở trung tâm vùng mười dặm đất trống được tôn là thánh địa như thần linh. Người bộ lạc tu dưới lòng đất hoặc đi quận Hỏa Yêu hấp thu hồn yêu binh đã chết; ai muốn ra ngoài phải qua khảo hạch đích thân của Âu Dương Hoa. Bộ lạc mơ ngày phá kén rung động chín quận.","nguon":["@c0573"]},{"id":"quan-kim-yeu","name":"Quận Kim Yêu","cn":"","type":"khac","typeLabel":"Quận yêu","diaBan":"Giáp ranh quận Hỏa Yêu","nhanVatChinh":[],"blurb":"Một trong các quận yêu, giáp ranh quận Hỏa Yêu ở vùng dãy núi chướng khí; quân Kim Yêu không quản nơi đó.","detail":"Quận Kim Yêu giáp ranh quận Hỏa Yêu tại vùng dãy núi lớn quanh năm chướng khí. Cả quân Hỏa Yêu lẫn quân Kim Yêu đều không quản vùng này, để tòa thành trắng của Lão tổ ẩn cư bên trong.","nguon":["@c0574"]},{"id":"quan-thien-yeu-faction","name":"Quận Thiên Yêu","cn":"","type":"khac","typeLabel":"Quận yêu","diaBan":"Một trong các quận Thiên Yêu","nhanVatChinh":[],"blurb":"Nơi tiểu đội bắt người trước kia của Lão tổ bị giết sạch không truyền lại tin.","detail":"Quận Thiên Yêu là nơi tiểu đội bắt người trước kia của Lão tổ thành trắng bị giết sạch, không kịp truyền tin về, khiến Lão tổ chưa tra được tu vi của Vương Lâm.","nguon":["@c0574"]},{"id":"tu-si-lien-minh","name":"Tu sĩ Liên minh","cn":"","type":"to-chuc","typeLabel":"Tổ chức","diaBan":"Vùng chướng khí giao giới Hoả Yêu Quận và Kim Yêu Quận","nhanVatChinh":["Lão Tổ Liên minh","Tiên vệ"],"blurb":"Tổ chức do Tiên giới Lão Tổ đứng đầu, căn cứ ở vùng chướng khí bí mật, nắm Tiên chủng khống chế thuộc hạ.","detail":"Tổ chức của các tu sĩ liên minh do Tiên giới Lão Tổ đứng đầu, căn cứ ẩn trong vùng chướng khí bí mật ở giao giới phía bắc Hoả Yêu Quận và Kim Yêu Quận. Lão Tổ dùng Tiên chủng khống chế thuộc hạ và sở hữu hơn mười Tiên vệ tu vi Vấn Đỉnh giả. Trở thành mục tiêu chinh phạt của Vương Lâm sau khi Lão Tổ hai lần trêu chọc hắn.","nguon":["@c0576"]},{"id":"tien-gioi-the-luc","name":"Tiên giới","cn":"","type":"khac","typeLabel":"Cảnh giới / nguồn gốc","diaBan":"Tiên giới","nhanVatChinh":["Lão Tổ Liên minh"],"blurb":"Cảnh giới nguồn gốc mà Lão Tổ tự xưng đến từ; chỗ dựa khiến đám tu sĩ kính sợ.","detail":"Lão Tổ chủ Toà thành trắng tự xưng là Tiên nhân đến từ Tiên giới. Lai lịch này là chỗ dựa của đám tu sĩ phiêu phù bên ngoài thành, khiến họ kính sợ uy thế của Lão Tổ.","nguon":["@c0577"]},{"id":"loi-yeu-quan","name":"Lôi Yêu Quận","cn":"","type":"yeu-toc","typeLabel":"Quận yêu tộc","diaBan":"Yêu Linh chi địa","nhanVatChinh":["Lôi Suất"],"blurb":"Một trong bảy Quận của Yêu Linh, lôi hệ; phái mười vạn yêu binh do Lôi Suất dẫn đầu vây phương Bắc Luyện Hồn bộ lạc.","detail":"Một trong bảy Quận của Yêu Linh, hệ lôi. Lần này tách mười vạn yêu binh do Phó soái Lôi Suất dẫn đầu, vây phương Bắc Luyện Hồn bộ lạc với dã tâm chiếm đoạt dị bảo màn sương đen (Tôn Hồn Phiên) để dâng Yêu Đế. Lôi Suất phá được một lỗ hổng màn sương nhưng bị Vương Lâm định thân đánh văng.","nguon":["@c0583"]},{"id":"thuy-yeu-quan","name":"Thuỷ Yêu Quận","cn":"","type":"yeu-toc","typeLabel":"Quận yêu tộc","diaBan":"Yêu Linh chi địa","nhanVatChinh":["Nữ Phó soái Thuỷ Yêu Quận","Yêu Tương (Thuỷ Yêu Quận)"],"blurb":"Một trong bảy Quận của Yêu Linh; phái mười vạn yêu binh do nữ Phó soái dẫn đầu vây phương Nam, mưu bắt tộc nhân bộ lạc về nghiên cứu.","detail":"Một trong bảy Quận của Yêu Linh. Lần này tách mười vạn yêu binh do nữ Phó soái dẫn đầu, đi cùng Yêu Tương bản Quận, vây phương Nam Luyện Hồn bộ lạc. Ước định để Lôi Yêu Quận lấy dị bảo, còn mình bắt toàn bộ tộc nhân về nghiên cứu. Khi Vương Lâm thi triển Định Thân thuật, quân Thuỷ Yêu bị định trụ; nữ Phó soái thoát ra bỏ chạy.","nguon":["@c0583"]},{"id":"yeu-linh-that-quan","name":"Yêu Linh (thất Quận)","cn":"","type":"yeu-toc","typeLabel":"Liên hợp Quận yêu tộc","diaBan":"Yêu Linh chi địa","nhanVatChinh":["Yêu Đế","Lôi Suất","Nữ Phó soái Thuỷ Yêu Quận"],"blurb":"Tập hợp bảy Quận yêu tộc dưới Yêu Đế; hai Quận Thuỷ và Lôi đánh Luyện Hồn bộ lạc, năm Quận còn lại giao chiến ở chiến trường khác.","detail":"Tập hợp bảy Quận của Yêu Linh đặt dưới quyền Yêu Đế. Trong cuộc vây Luyện Hồn bộ lạc, chỉ đầu lĩnh của hai Quận Thuỷ Yêu và Lôi Yêu lấy bộ lạc làm mục tiêu; năm Quận còn lại tiếp tục chiến đấu ở các chiến trường của Hoả Yêu Quận. Không Quận nào dốc toàn lực như Thiên Yêu Quận.","nguon":["@c0583"]},{"id":"mac-mon","name":"Mặc môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Yêu Linh","nhanVatChinh":["Mộ Dung Trác"],"blurb":"Tông môn của Mộ Dung Trác — vị Mặc môn tứ đại đệ tử.","detail":"Tông môn nơi Mộ Dung Trác là tứ đại đệ tử. Đệ tử Mặc môn được biết tới qua tính trầm mặc và thần thông cảm tri đặc biệt.","nguon":["@c0589"]},{"id":"phu-van-phai","name":"Phù Vân phái","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Yêu Linh","nhanVatChinh":["Triệu Y Huyên","Từ Phi (Phù Vân phái)"],"blurb":"Tông môn của Triệu Y Huyên và sư muội Từ Phi.","detail":"Tông môn nơi Triệu Y Huyên và Từ Phi tu luyện. Triệu Y Huyên là đệ tử nổi bật với khả năng nhìn thấu nội tâm người khác.","nguon":["@c0589"]},{"id":"he-phai-thien-van-tu","name":"Hệ phái Thiên Vận Tử (xích hệ / tử hệ)","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Đỗ Kiến","Thiên Vận Tử"],"blurb":"Hệ thống phân tầng đệ tử của Thiên Vận Tử, gồm xích hệ và tử hệ; Đỗ Kiến thuộc xích hệ.","detail":"Hệ thống phân tầng đệ tử của Thiên Vận Tử. Đỗ Kiến thuộc xích hệ, còn địa vị tử hệ được nhắc tới như mức cao hơn. Đỗ Kiến lo sợ Vương Lâm sẽ vọt lên địa vị tử hệ về sau.","nguon":["@c0589"]},{"id":"huong-gia-dong-lam-tinh","name":"Hướng gia (Đông Lâm tinh)","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Đông Lâm tinh","nhanVatChinh":[],"blurb":"Gia tộc ở Đông Lâm tinh mà Vương Lâm định tới dò thân phận nữ tử trong tranh.","detail":"Hướng gia là gia tộc tại Đông Lâm tinh. Nữ tử trong tranh nói lão tổ của tộc nàng có thể khiến Uyển nhi sống lại, nên Vương Lâm dự định tới Hướng gia để dò thân phận và động cơ thật của nàng.","nguon":["@c0613","@c0612"]},{"id":"van-tien-dao-lu","name":"Vân Tiên đạo lữ","cn":"","type":"khac","typeLabel":"Cặp tu sĩ","diaBan":"Vùng đất Yêu Linh","nhanVatChinh":["Vương Tạ","Hồ Quyên"],"blurb":"Chỉ Vương Tạ và Hồ Quyên, một nam một nữ ngồi trên mây lành hư ảo; được các lão quái cố kỵ.","detail":"Vân Tiên đạo lữ là cách gọi cặp Vương Tạ (nam) và Hồ Quyên (nữ), xuất hiện trên cụm mây lành hư ảo. Họ giam giữ Tham Lang và Thần Long trong túi trữ vật. Tu vi của họ khiến các lão quái như Lăng Thiên Hậu cực kỳ cố kỵ, không dám ra tay.","nguon":["@c0614"]},{"id":"nhiem-gia","name":"Nhiễm gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu chân huyết thống","diaBan":"Nhiễm Vân Tinh, La Thiên Tinh Vực","nhanVatChinh":["Nhiễm Nguyệt","Nhiễm Thần","Nhiễm Phong"],"blurb":"Gia tộc tu chân huyết thống ở Nhiễm Vân Tinh thuộc La Thiên Tinh Vực; bốn người trong chương phần lớn là người Nhiễm gia.","detail":"Tại La Thiên Tinh Vực không có môn phái, chỉ có các tu chân gia tộc huyết thống; Nhiễm gia là một trong số đó, cư trú tại Nhiễm Vân Tinh. Nhiễm Nguyệt, Nhiễm Thần, Nhiễm Phong là người Nhiễm gia (Tôn Tuyết Sơn đi cùng), bị Minh vụ trùng vây khi thí luyện và được Vương Lâm giải cứu; Nhiễm Nguyệt hứa Nhiễm gia sẽ báo đáp.","nguon":["@c0615","@c0616"],"aliases":["Nhiễm gia cửu đại tộc"]},{"id":"huyen-gia","name":"Huyễn gia","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Thiên Huyễn Tinh (bắc vực chủ tinh La Thiên Tinh Vực)","nhanVatChinh":["Lão già (đại trưởng lão Huyễn gia)","Mi nhi"],"blurb":"Gia tộc trên Thiên Huyễn Tinh; lão già đưa Mi nhi đi là đại trưởng lão của gia tộc.","detail":"Huyễn gia là gia tộc trên Thiên Huyễn Tinh, bắc vực chủ tinh của La Thiên Tinh Vực. Lão già đưa Mi nhi rời đi chính là đại trưởng lão Huyễn gia, đã gặp nhiều thế hệ hậu bối nhưng ít người tư chất sánh được Mi nhi.","nguon":["@c0616"]},{"id":"ton-gia-la-thien","name":"Tôn gia","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Nhiễm Vân Tinh","nhanVatChinh":[],"blurb":"Thế lực chủ quản tòa thành trì cự thạch xanh nơi Vương Lâm dừng chân ẩn nấp.","detail":"Tôn gia chủ quản tòa thành trì cự thạch xanh đề hai chữ Tôn gia, nơi Vương Lâm vào ẩn nấp. Thành chủ yếu là phàm nhân nhưng tu sĩ nhiều; có động phủ ở thành bắc cho tu sĩ ngoại lai thuê. Tu sĩ ngoại lai thường tới kết nghĩa anh em để mượn linh lực Tôn gia.","nguon":["@c0616"]},{"id":"hua-gia-thien-huyen","name":"Hứa gia","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Thiên Huyễn Tinh bắc vực","nhanVatChinh":[],"blurb":"Dòng họ lớn, lâu đời, danh giá quyền thế ở Thiên Huyễn Tinh bắc vực.","detail":"Hứa gia là dòng họ lớn, lâu đời, danh giá quyền thế ở Thiên Huyễn Tinh bắc vực. Khi Vương Lâm xưng họ Hứa (tên giả Hứa Mộc), Nhiễm Nguyệt chấn động vì nghi hắn là người Hứa gia, càng thêm lo sợ.","nguon":["@c0616"]},{"id":"la-thien-tinh-vuc-the-luc","name":"La Thiên Tinh Vực","cn":"","type":"vung","typeLabel":"Tinh vực","diaBan":"La Thiên tinh vực (bao quát Nhiễm Vân Tinh)","nhanVatChinh":["Vương Lâm"],"blurb":"Khu vực nơi loại pháp thuật nhỏ mạnh hơn nhiều so với Tu Chân Liên Minh; tiên ngọc lượng lớn chỉ tu sĩ Vấn Đỉnh hoặc gia tộc thế lực của vùng mới có.","detail":"Vương Lâm đánh giá pháp thuật nhỏ (như trận pháp trong hạt châu xanh) ở La Thiên Tinh Vực mạnh hơn nhiều so với Tu Chân Liên Minh. Lượng tiên ngọc lớn mà Vương Lâm cần chỉ có ở tu sĩ Vấn Đỉnh hoặc gia tộc thế lực của vùng này.","nguon":["@c0617"]},{"id":"bao-hop-lau","name":"Bảo Hợp Lâu","cn":"","type":"thuong-hoi","typeLabel":"Cửa hàng giao dịch","diaBan":"Cuối thành đông (thành tu sĩ)","nhanVatChinh":["Lô Phong","Tôn lão"],"blurb":"Tòa lầu các giao dịch lớn bậc nhất cuối thành đông, bày trận pháp tám khối thượng phẩm nguyên linh thạch, quy củ ‘hai không tiến, một không ra’.","detail":"Tòa lầu các lớn cuối thành đông, trước cửa bày trận pháp tám khối thượng phẩm nguyên linh thạch cao ba trượng, có tầng phòng vệ ngăn thần thức. Quy củ ‘hai không tiến, một không ra’: tu vi dưới Nguyên Anh không tiến, không có mười vạn linh thạch không tiến, vào rồi không giao dịch được thì không ra. Lô Phong gác cửa kiểm tra tiêu chuẩn khách, Tôn lão có vị trí siêu nhiên trong lâu.","nguon":["@c0618"]},{"id":"thanh-truc-cac","name":"Thanh Trúc Các","cn":"","type":"thuong-hoi","typeLabel":"Cửa hàng giao dịch","diaBan":"Thành đông (thành tu sĩ)","nhanVatChinh":["Văn sĩ trẻ Thanh Trúc Các"],"blurb":"Cửa hàng hai tầng thành đông, hoành tráng mà thanh lịch, linh thạch chất lượng cực tốt, văn sĩ trẻ coi cửa hiền hòa nhiệt tình.","detail":"Cửa hàng hai tầng ở thành đông, hoành tráng mà thanh lịch, khối linh thạch chất lượng cực tốt phô trước cửa. Bên trong đầy giá gỗ với các hộp nhỏ đặt pháp bảo, đan dược trên lớp vải lụa vàng. Một văn sĩ trẻ tu vi Hóa Thần sơ kỳ coi cửa, thái độ hiền hòa nhiệt tình, khác hẳn Lô Phong ở Bảo Hợp Lâu.","nguon":["@c0618"]},{"id":"ton-gia-nhiem-van-tinh","name":"Tôn Gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Nhiễm Vân Tinh (tòa thành nơi Vương Lâm trú)","nhanVatChinh":["Tôn Khải Minh"],"blurb":"Gia tộc kiểm soát tòa thành nơi Vương Lâm trú tại Nhiễm Vân Tinh, do Tôn Khải Minh phụ trách; có lão tổ tu vi Vấn Đỉnh.","detail":"Tôn Gia là gia tộc kiểm soát tòa thành phía Bắc nơi Vương Lâm ẩn thân tại Nhiễm Vân Tinh. Tôn Khải Minh — lão già hắc y — phụ trách tòa thành. Gia tộc có lão tổ tu vi Vấn Đỉnh. Họ giao cho Vương Lâm hai mươi vạn tiên ngọc, đồng thời phái Tôn Khải Minh thăm dò tu vi của hắn (dưới danh Hứa Mộc).","nguon":["@c0621"]},{"id":"nhiem-gia-nhiem-van-tinh","name":"Nhiễm Gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Nhiễm Vân Tinh","nhanVatChinh":[],"blurb":"Gia tộc sở hữu Bảo Hợp Lâu, tổ chức đấu giá trong thành bảy ngày sau với một viên bát phẩm thứ thần đan.","detail":"Nhiễm Gia là gia tộc sở hữu Bảo Hợp Lâu tại Nhiễm Vân Tinh. Họ tổ chức cuộc đấu giá trong thành bảy ngày sau thời điểm Tôn Khải Minh gặp Vương Lâm, trong đó có một viên bát phẩm thứ thần đan.","nguon":["@c0621"]}]};
